     2	import {
     3	  NodeTypes,
     4	  type SimpleExpressionNode,
     5	  createSimpleExpression,
     6	} from '../ast'
     7	import type { NodeTransform } from '../transform'
     8	import { ErrorCodes, createCompilerError } from '../errors'
     9	import { validFirstIdentCharRE } from '../utils'
    10	
    11	export const transformVBindShorthand: NodeTransform = (node, context) => {
    12	  if (node.type === NodeTypes.ELEMENT) {
    13	    for (const prop of node.props) {
    14	      // same-name shorthand - :arg is expanded to :arg="arg"
    15	      if (
    16	        prop.type === NodeTypes.DIRECTIVE &&
    17	        prop.name === 'bind' &&
    18	        !prop.exp
    19	      ) {
    20	        const arg = prop.arg!
    21	        if (arg.type !== NodeTypes.SIMPLE_EXPRESSION || !arg.isStatic) {
    22	          // only simple expression is allowed for same-name shorthand
    23	          context.onError(
    24	            createCompilerError(
    25	              ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
    26	              arg.loc,
    27	            ),
    28	          )
    29	          prop.exp = createSimpleExpression('', true, arg.loc)
    30	        } else {
    31	          const propName = camelize((arg as SimpleExpressionNode).content)
    32	          if (
    33	            validFirstIdentCharRE.test(propName[0]) ||
    34	            // allow hyphen first char for https://github.com/vuejs/language-tools/pull/3424
    35	            propName[0] === '-'
    36	          ) {
    37	            prop.exp = createSimpleExpression(propName, false, arg.loc)
    38	          }
    39	        }
    40	      }
    41	    }
    42	  }
    43	}

