action.new_str:
test('same-name shorthand without expression in DOM template', () => {
  // In actual usage, this is parsed by browser which turns `<div :arg>` into `<div :arg="">`
  // but without our fix, an empty simple expression could result in undefined `exp` and crash
  // during compile time type checks for in-DOM compilation

  ;(global as any).__BROWSER__ = true
  const { root, problems } = parseWithVBind('<div :arg=""></div>')

  // It should compile correctly and not throw
  expect(problems.length).toBe(0)
  // properties[0].value because transformElement transforms it to an object argument natively
  const codegenNode = root.children[0].codegenNode as any
  expect(codegenNode.props.properties[0].key.content).toBe('arg')
  expect(codegenNode.props.properties[0].value.content).toBe('arg')
  ;(global as any).__BROWSER__ = false
})

